using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class FileController : ControllerBase
{
    private readonly string _uploadPath = Path.Combine(Directory.GetCurrentDirectory(), "uploads");

    [HttpGet("{filename}")]
    public async Task<IActionResult> GetFile(string filename)
    {
        if (string.IsNullOrEmpty(filename))
        {
            return BadRequest("Filename is required.");
        }

        // Canonicalize the filename to prevent path traversal
        var sanitizedFilename = Path.GetFileName(filename);
        
        // Ensure we're not trying to access parent directories
        if (filename.Contains("..") || filename.StartsWith("/") || filename.StartsWith("\\"))
        {
            return BadRequest("Invalid filename.");
        }

        var filePath = Path.Combine(_uploadPath, sanitizedFilename);

        // Ensure the file path is within the upload directory
        var uploadDirectory = new DirectoryInfo(_uploadPath);
        var fileDirectory = new DirectoryInfo(filePath);
        
        if (!fileDirectory.FullName.StartsWith(uploadDirectory.FullName, StringComparison.OrdinalIgnoreCase))
        {
            return BadRequest("Access denied.");
        }

        if (!System.IO.File.Exists(filePath))
        {
            return NotFound("File not found.");
        }

        var fileExtension = Path.GetExtension(filePath).ToLowerInvariant();
        string contentType = GetContentType(fileExtension);

        var fileStream = new FileStream(filePath, FileMode.Open, FileAccess.Read, FileShare.Read, 8192, true);
        return File(fileStream, contentType, sanitizedFilename);
    }

    private string GetContentType(string extension)
    {
        return extension switch
        {
            ".pdf" => "application/pdf",
            ".jpg" or ".jpeg" => "image/jpeg",
            ".png" => "image/png",
            ".gif" => "image/gif",
            ".bmp" => "image/bmp",
            ".tiff" or ".tif" => "image/tiff",
            ".txt" => "text/plain",
            ".html" or ".htm" => "text/html",
            ".css" => "text/css",
            ".js" => "application/javascript",
            ".json" => "application/json",
            ".xml" => "application/xml",
            ".doc" or ".docx" => "application/msword",
            ".xls" or ".xlsx" => "application/vnd.ms-excel",
            ".ppt" or ".pptx" => "application/vnd.ms-powerpoint",
            ".zip" => "application/zip",
            ".rar" => "application/vnd.rar",
            ".7z" => "application/x-7z-compressed",
            _ => "application/octet-stream"
        };
    }
}